import type { FeedConfig, FeedItem } from "../../types.js";

/**
 * Convert Markdown body (bullet-list based) to HTML.
 * Handles:
 *   - `- item` → `<ul><li>item</li></ul>`
 *   - `**bold**` → `<strong>bold</strong>`
 *   - `` `code` `` → `<code>code</code>`
 *   - `[text](url)` → `<a href="url">text</a>`
 */
function mdToHtml(mdBody: string): string {
  const lines = mdBody.split("\n");
  const htmlParts: string[] = [];
  let inList = false;

  for (const line of lines) {
    const trimmed = line.trim();

    if (trimmed.startsWith("- ")) {
      const content = trimmed.slice(2).trim();
      let html = content
        .replace(/\*\*(.+?)\*\*/g, "<strong>$1</strong>")
        .replace(/`([^`]+)`/g, "<code>$1</code>")
        .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>');

      if (!inList) {
        htmlParts.push("<ul>");
        inList = true;
      }
      htmlParts.push(`  <li>${html}</li>`);
    } else {
      if (inList) {
        htmlParts.push("</ul>");
        inList = false;
      }
      if (trimmed && !trimmed.startsWith("#") && !trimmed.startsWith("---")) {
        htmlParts.push(`<p>${trimmed}</p>`);
      }
    }
  }

  if (inList) {
    htmlParts.push("</ul>");
  }

  return htmlParts.join("\n");
}

export async function fetchFeed(config: FeedConfig): Promise<FeedItem[]> {
  // 1. Fetch the raw CHANGELOG.md
  const res = await fetch(config.url);
  const md = await res.text();

  // 2. Parse version sections (## X.Y.Z)
  const lines = md.split("\n");
  interface VersionEntry {
    version: string;
    body: string;
  }
  const versions: VersionEntry[] = [];
  let currentVersion = "";
  const bodyLines: string[] = [];

  for (let i = 0; i < lines.length; i++) {
    const match = lines[i].match(/^## (\d+\.\d+\.\d+)\s*$/);
    if (match) {
      if (currentVersion) {
        versions.push({ version: currentVersion, body: bodyLines.join("\n") });
      }
      currentVersion = match[1];
      bodyLines.length = 0;
    } else {
      bodyLines.push(lines[i]);
    }
  }
  if (currentVersion) {
    versions.push({ version: currentVersion, body: bodyLines.join("\n") });
  }

  // 3. Fetch GitHub tags to get release dates
  const tagDateMap = new Map<string, string>();
  try {
    // Collect all tags via pagination (typically 2-3 pages of 100)
    const allTags: { version: string; commitSha: string }[] = [];
    for (let page = 1; page <= 10; page++) {
      const tagUrl = `https://api.github.com/repos/anthropics/claude-code/tags?per_page=100&page=${page}`;
      const tagRes = await fetch(tagUrl, {
        headers: { Accept: "application/vnd.github.v3+json" },
      });
      if (!tagRes.ok) break;
      const tags: any[] = await tagRes.json();
      if (tags.length === 0) break;
      for (const tag of tags) {
        allTags.push({
          version: tag.name.replace(/^v/, ""),
          commitSha: tag.commit.sha,
        });
      }
    }

    // Fetch commit dates for all tags concurrently
    const dateResults = await Promise.all(
      allTags.map(async (tag) => {
        try {
          const commitUrl = `https://api.github.com/repos/anthropics/claude-code/commits/${tag.commitSha}`;
          const commitRes = await fetch(commitUrl, {
            headers: { Accept: "application/vnd.github.v3+json" },
          });
          if (commitRes.ok) {
            const commit: any = await commitRes.json();
            const date =
              commit.commit?.committer?.date || commit.commit?.author?.date;
            if (date) return { version: tag.version, date };
          }
        } catch {
          // Individual tag fetch failure is non-fatal
        }
        return null;
      })
    );

    for (const result of dateResults) {
      if (result) {
        tagDateMap.set(result.version, result.date);
      }
    }
  } catch {
    // Tags API failure is non-fatal — fallback dates will be used
  }

  // 4. Build FeedItems with best-effort dates
  const today = new Date().toISOString();
  const items: FeedItem[] = [];

  for (let idx = 0; idx < versions.length; idx++) {
    const v = versions[idx];
    let date: string;

    if (tagDateMap.has(v.version)) {
      date = tagDateMap.get(v.version)!;
    } else {
      // Fallback: use the nearest version that has a tag date.
      // Search upward (newer versions = lower index) then downward (older = higher index).
      let fallbackDate = today;
      for (let j = idx - 1; j >= 0; j--) {
        if (tagDateMap.has(versions[j].version)) {
          fallbackDate = tagDateMap.get(versions[j].version)!;
          break;
        }
      }
      if (fallbackDate === today) {
        for (let j = idx + 1; j < versions.length; j++) {
          if (tagDateMap.has(versions[j].version)) {
            fallbackDate = tagDateMap.get(versions[j].version)!;
            break;
          }
        }
      }
      date = fallbackDate;
    }

    const contentHtml = mdToHtml(v.body);

    items.push({
      id: `claude-code-v${v.version}`,
      title: `v${v.version}`,
      url: `https://github.com/anthropics/claude-code/releases/tag/v${v.version}`,
      publishedAt: date,
      contentHtml,
      source: config.slug,
    });
  }

  return items;
}
